#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int longestSubstring(string s, int k) {
        if (k == 0 || s.empty()) {
            return 0;
        }

        unordered_map<char, int> charCount;
        int left = 0;
        int maxLength = 0;

        for (int right = 0; right < s.size(); ++right) {
            charCount[s[right]]++;

            while (charCount.size() > k) {
                charCount[s[left]]--;
                if (charCount[s[left]] == 0) {
                    charCount.erase(s[left]);
                }
                left++;
            }

            maxLength = max(maxLength, right - left + 1);
        }

        return maxLength;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string s;
    if (!(cin >> s)) return 0;
    int k;
    if (!(cin >> k)) return 0;
    Solution sol;
    int ans = sol.longestSubstring(s, k);
    cout << ans << "\n";
    return 0;
}
